svg.script:

console.clear();
console.log('═══════════════════════════════════════');
console.log('🔍 SVG WITH IFRAME TO ai.planet.com');
console.log('═══════════════════════════════════════');

console.log('✅ SVG loaded successfully');
console.log('📍 Attempting to load iframe to: https://ai.planet.com/');

// Track iframe loading status
var iframeLoaded = false;

// Function to check iframe status
function checkIframe() {
  var fo = document.querySelector('foreignObject');
  if (fo) {
    var div = fo.querySelector('div');
    if (div) {
      var iframe = div.querySelector('iframe');
      if (iframe) {
        console.log('  ✅ iframe element found');
        console.log('  📍 iframe src:', iframe.src);
        console.log('  📍 iframe sandbox:', iframe.sandbox.value || 'none');

        // Add load event listener if not already added
        if (!iframe._listenerAdded) {
          iframe._listenerAdded = true;

          iframe.onload = function() {
            iframeLoaded = true;
            console.log('  ✅ IFRAME LOADED SUCCESSFULLY!');
            console.log('  📍 iframe URL:', iframe.src);
            console.log('  📍 iframe readyState:', iframe.contentDocument ? iframe.contentDocument.readyState : 'N/A');

            try {
              if (iframe.contentWindow) {
                console.log('  📍 iframe contentWindow available');
                console.log('  📍 contentWindow.location:', iframe.contentWindow.location.href);
                console.log('  📍 contentWindow.origin:', iframe.contentWindow.origin || 'N/A');
              }
            } catch(e) {
              console.warn('  ⚠️ Cannot access contentWindow (CORS):', e.message);
            }
          };

          iframe.onerror = function(e) {
            console.error('  ❌ iframe error:', e);
          };
        }
      }
    }
  }
}

// Check immediately and after delay
checkIframe();

// Also check after window loads
window.addEventListener('load', function() {
  console.log('\n📌 Window load event fired');
  checkIframe();

  // Check iframe content after load
  setTimeout(function() {
    var fo = document.querySelector('foreignObject');
    if (fo) {
      var div = fo.querySelector('div');
      if (div) {
        var iframe = div.querySelector('iframe');
        if (iframe) {
          console.log('\n📌 Final status check:');
          console.log('  📍 iframe.src:', iframe.src);
          console.log('  📍 iframe.complete:', iframe.complete || 'N/A');
          console.log('  📍 iframe readyState:', iframe.contentDocument ? iframe.contentDocument.readyState : 'N/A');
          console.log('  📍 iframe loaded:', iframeLoaded ? '✅ YES' : '⏳ Still loading or error');

          // Check if content loaded
          try {
            if (iframe.contentDocument && iframe.contentDocument.body) {
              console.log('  📍 Content loaded! Title:', iframe.contentDocument.title || 'No title');
              console.log('  📍 Body length:', iframe.contentDocument.body.innerHTML.length || 0);
            }
          } catch(e) {
            console.warn('  ⚠️ Cannot access contentDocument (CORS):', e.message);
          }
        }
      }
    }
  }, 3000);
});

console.log('\n⏱️ Test running...');
console.log('═══════════════════════════════════════');
